def solve(grid):
    from collections import Counter
    h, w = len(grid), len(grid[0])
    counts = Counter()
    for r in range(h):
        for c in range(w):
            if grid[r][c] != 0:
                counts[grid[r][c]] += 1
    unique_pos = None
    unique_color = None
    for r in range(h):
        for c in range(w):
            v = grid[r][c]
            if v != 0 and counts[v] == 1:
                unique_color = v
                unique_pos = (r, c)
    out = [[0]*w for _ in range(h)]
    if unique_pos:
        ur, uc = unique_pos
        out[ur][uc] = unique_color
        for dr in [-1, 0, 1]:
            for dc in [-1, 0, 1]:
                nr, nc = ur+dr, uc+dc
                if 0 <= nr < h and 0 <= nc < w and (dr != 0 or dc != 0):
                    out[nr][nc] = 2
    return out

