def solve(grid):
    h, w = len(grid), len(grid[0])
    out = [row[:] for row in grid]
    visited = [[False]*w for _ in range(h)]
    def flood4(r, c):
        cells = []
        stack = [(r, c)]
        while stack:
            cr, cc = stack.pop()
            if 0 <= cr < h and 0 <= cc < w and not visited[cr][cc] and grid[cr][cc] == 4:
                visited[cr][cc] = True
                cells.append((cr, cc))
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    stack.append((cr+dr, cc+dc))
        return cells
    groups = []
    for r in range(h):
        for c in range(w):
            if grid[r][c] == 4 and not visited[r][c]:
                groups.append(sorted(flood4(r, c)))
    template_idx = None
    for gi, g in enumerate(groups):
        for r, c in g:
            for dr in range(-2, 3):
                for dc in range(-2, 3):
                    nr, nc = r+dr, c+dc
                    if 0 <= nr < h and 0 <= nc < w and grid[nr][nc] in (1, 3):
                        template_idx = gi
                        break
                if template_idx is not None: break
            if template_idx is not None: break
        if template_idx is not None: break
    def find_adj_2(g):
        for r, c in g:
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < h and 0 <= nc < w and grid[nr][nc] == 2:
                    return (nr, nc)
        return None
    tg = groups[template_idx]
    t2 = find_adj_2(tg)
    t_rel = tuple(sorted((r - t2[0], c - t2[1]) for r, c in tg))
    t_decos = []
    for r in range(h):
        for c in range(w):
            if grid[r][c] in (1, 3):
                if any(abs(r-gr) <= 2 and abs(c-gc) <= 2 for gr, gc in tg):
                    t_decos.append((r - t2[0], c - t2[1], grid[r][c]))
    transforms = [
        lambda r,c: (r,c), lambda r,c: (c,-r), lambda r,c: (-r,-c), lambda r,c: (-c,r),
        lambda r,c: (r,-c), lambda r,c: (-r,c), lambda r,c: (c,r), lambda r,c: (-c,-r),
    ]
    for gi, g in enumerate(groups):
        if gi == template_idx: continue
        g2 = find_adj_2(g)
        g_rel = tuple(sorted((r - g2[0], c - g2[1]) for r, c in g))
        for fn in transforms:
            transformed = tuple(sorted(fn(r,c) for r,c in t_rel))
            if transformed == g_rel:
                for dr, dc, v in t_decos:
                    nr, nc = fn(dr, dc)
                    ar, ac = nr + g2[0], nc + g2[1]
                    if 0 <= ar < h and 0 <= ac < w:
                        out[ar][ac] = v
                break
    return out

